"use strict";(self.webpackChunklindb_doc=self.webpackChunklindb_doc||[]).push([[9045],{206:(t,e,d)=>{d.r(e),d.d(e,{default:()=>c});var a=d(6252);const r=[(0,a.uE)('<h1 id="数据模型" tabindex="-1"><a class="header-anchor" href="#数据模型" aria-hidden="true">#</a> 数据模型</h1><h2 id="时间序列术语" tabindex="-1"><a class="header-anchor" href="#时间序列术语" aria-hidden="true">#</a> 时间序列术语</h2><table><thead><tr><th>术语</th><th>描述</th></tr></thead><tbody><tr><td>Namespace</td><td>命名空间，类似database name</td></tr><tr><td>Metric Name</td><td>指标名</td></tr><tr><td>Tags</td><td>每个指标名下面可以加多个 Key/Value 类型的 Tag</td></tr><tr><td>Time Series</td><td>时间线，Metric Name + Tags 的组合对应一条时间线</td></tr><tr><td>Field</td><td>一个指标下面可以有多个字段</td></tr><tr><td>Data Point</td><td>一个字段在相应时间点的数据点</td></tr></tbody></table><h2 id="时间序列唯一标识" tabindex="-1"><a class="header-anchor" href="#时间序列唯一标识" aria-hidden="true">#</a> 时间序列唯一标识</h2><p>每一个时间序列都由<code>指标名</code>与<code>标签</code>的键值对以及<code>字段</code>来唯一标识。 指标名记录了监控对象的具体意义（例如，cpu，即监控对象为cpu的资源使用情况），由于我们采用<code>pb</code>进行metric传输，无需进行正则检查，仅对该文本数据作长度检查。</p><p>标签记录的是可枚举的文本数据（例如，ip=1.1.1.1,zone=sh，即该机器的ip地址为1.1.1.1,生产区为上海）。在查询时，我们可以对这些标签来做过滤和聚合操作，比如查找单条ip地址的机器、查找多条ip地址的机器、前缀搜索50条ip地址的机器、搜索sh上产区的所有机器等。对于任一标签的修改及删除都会产生另外一条时间序列。</p><p>标签名称同样没有特别的限制，LinDB 默认限制 tag-key 的数量为32，标签组合数限制为10K;</p><p>字段对应的是文本到数值的键值对（例如，idle=32,system=10,user=20，即该条时间序列的空闲利用率为32、系统态用户态的利用率分别为10、20）。</p><p>除字段名之外，LinDB 中的字段存在字段类型的定义，不同的字段类型会在存储时进行聚合存放。详细内容可参考下一节。</p>',9)],i={},c=(0,d(3744).Z)(i,[["render",function(t,e){return(0,a.wg)(),(0,a.iD)("div",null,r)}]])},6598:(t,e,d)=>{d.r(e),d.d(e,{data:()=>a});const a=JSON.parse('{"key":"v-7c6af5a6","path":"/zh/docs/concept/datamodel.html","title":"数据模型","lang":"zh-CN","frontmatter":{},"excerpt":"","headers":[{"level":2,"title":"时间序列术语","slug":"时间序列术语","link":"#时间序列术语","children":[]},{"level":2,"title":"时间序列唯一标识","slug":"时间序列唯一标识","link":"#时间序列唯一标识","children":[]}],"git":{"updatedTime":1681286958000,"contributors":[{"name":"stone1100","email":"stonejh1100@gmail.com","commits":1}]},"filePathRelative":"zh/docs/concept/datamodel.md"}')}}]);